def gen(rng, size):
    n = max(1, min(size, 20000))
    apples = []
    days = []
    for _ in range(n):
        if rng.random() < 0.15:
            apples.append(0)
            days.append(0)
        else:
            apples.append(rng.randint(1, 20000))
            days.append(rng.randint(1, 20000))
    return [apples, days]

