class Solution:
    def eatenApples(self, apples, days):
        n = len(apples)
        stock = []
        eaten = 0
        day = 0
        while day < n or stock:
            if day < n and apples[day] > 0:
                stock.append([day + days[day] - 1, apples[day]])
            stock = [b for b in stock if b[0] >= day]
            if stock:
                stock.sort(key=lambda b: b[0])
                stock[0][1] -= 1
                eaten += 1
                if stock[0][1] == 0:
                    stock.pop(0)
            day += 1
        return eaten

