        n = len(apples)
        heap = []
        eaten = 0
        day = 0
        while day < n or heap:
            if day < n and apples[day] > 0:
                heapq.heappush(heap, [day + days[day], apples[day]])
            while heap and heap[0][0] <= day:
                heapq.heappop(heap)
            if heap:
                heap[0][1] -= 1
                eaten += 1
                if heap[0][1] == 0:
                    heapq.heappop(heap)
            day += 1
        return eaten

