var eatenApples = function(apples, days) {
    class MinHeap {
        constructor() { this.a = []; }
        size() { return this.a.length; }
        peek() { return this.a[0]; }
        push(x) {
            const a = this.a;
            a.push(x);
            let i = a.length - 1;
            while (i > 0) {
                const p = (i - 1) >> 1;
                if (a[p][0] <= a[i][0]) break;
                [a[p], a[i]] = [a[i], a[p]];
                i = p;
            }
        }
        pop() {
            const a = this.a;
            const top = a[0];
            const last = a.pop();
            if (a.length) {
                a[0] = last;
                let i = 0;
                while (true) {
                    let l = 2 * i + 1, r = 2 * i + 2, s = i;
                    if (l < a.length && a[l][0] < a[s][0]) s = l;
                    if (r < a.length && a[r][0] < a[s][0]) s = r;
                    if (s === i) break;
                    [a[s], a[i]] = [a[i], a[s]];
                    i = s;
                }
            }
            return top;
        }
    }
    const n = apples.length;
    const heap = new MinHeap();
    let eaten = 0;
    let day = 0;
    while (day < n || heap.size() > 0) {
        if (day < n && apples[day] > 0) {
            heap.push([day + days[day], apples[day]]);
        }
        while (heap.size() > 0 && heap.peek()[0] <= day) {
            heap.pop();
        }
        if (heap.size() > 0) {
            heap.peek()[1] -= 1;
            eaten += 1;
            if (heap.peek()[1] === 0) heap.pop();
        }
        day += 1;
    }
    return eaten;
};
